UPDATE engineering_articles SET body_html = REPLACE(body_html,
  '<h2>6. Расчёт на усталостную прочность (по Серенсену — Кинасошвили)</h2><p>Валы редукторов работают при циклическом изгибе (нормальные напряжения изменяются по симметричному циклу из-за вращения) и постоянном или пульсирующем кручении. Поэтому статической проверки недостаточно — обязателен расчёт по запасам усталостной прочности по нормальным s<sub>σ</sub> и касательным s<sub>τ</sub> напряжениям, и общий запас [1, с. 307; 5, с. 162]:</p>',
  '<h2>6. Расчёт на усталостную прочность (по Серенсену — Кинасошвили)</h2><p>Валы редукторов работают при циклическом изгибе (нормальные напряжения изменяются по симметричному циклу из-за вращения) и постоянном или пульсирующем кручении. Поэтому статической проверки недостаточно — обязателен расчёт по запасам усталостной прочности. В отечественной школе расчёта канонической является методика С. В. Серенсена и Р. С. Кинасошвили [6], положенная в основу <strong>Р 50-83-88 «Расчёты и испытания на прочность. Расчёты на прочность валов и осей»</strong> [16] — официального документа Госстандарта СССР, действующего в РФ для подтверждения долговечности валов в КБ. Альтернативные обзоры подходов даны в справочнике Серенсена-Когаева-Шнейдеровича [7], в справочнике Когаева-Махутова-Гусенкова [8], а также у Биргера-Шорра-Иосилевича [9] и Иванова [5]. Общий запас по нормальным s<sub>σ</sub> и касательным s<sub>τ</sub> напряжениям [1, с. 307; 5, с. 162; 6, гл. 3]:</p>'
)
WHERE slug = 'raschet-vala-na-prochnost-i-zhestkost-kompas-apm-fem';